        x: 6
        y: 22
        w: 56
        h: 68
        spec:
          $schema: https://vega.github.io/schema/vega-lite/v5.json
          background: transparent
          data:
            values:
              - { quarter: Q1, arr: 1.2 }
              - { quarter: Q2, arr: 1.6 }
              - { quarter: Q3, arr: 2.4 }
              - { quarter: Q4, arr: 3.3 }
